class Solution:
    def findMaintenanceWindow(self, n: int, w: int, scores: List[int]) -> List[int]:
        if n < w:
            return [-1, 0]

        window_sum = 0
        zero_count = 0
        for i in range(w):
            window_sum += scores[i]
            if scores[i] == 0:
                zero_count += 1

        best_start = -1
        min_sum = 10**18
        # 首个窗口合法则记录
        if zero_count == 0:
            min_sum = window_sum
            best_start = 0

        for start in range(1, n - w + 1):
            out_val = scores[start - 1]
            in_val = scores[start + w - 1]
            window_sum += in_val - out_val
            if out_val == 0:
                zero_count -= 1
            if in_val == 0:
                zero_count += 1
            # 严格更小才更新，保证平局取最早起点
            if zero_count == 0 and window_sum < min_sum:
                min_sum = window_sum
                best_start = start

        if best_start == -1:
            return [-1, 0]
        return [best_start, min_sum]
```

```java
public class Solution {
    public int[] findMaintenanceWindow(int n, int w, int[] scores) {
        if (n < w) return new int[] {-1, 0};

        long windowSum = 0;
        int zeroCount = 0;
        for (int i = 0; i < w; i++) {
            windowSum += scores[i];
            if (scores[i] == 0) zeroCount++;
        }

        int bestStart = -1;
        long minSum = Long.MAX_VALUE;
        if (zeroCount == 0) {
            minSum = windowSum;
            bestStart = 0;
        }

        for (int start = 1; start <= n - w; start++) {
            int outVal = scores[start - 1];
            int inVal = scores[start + w - 1];
            windowSum += inVal - outVal;
            if (outVal == 0) zeroCount--;
            if (inVal == 0) zeroCount++;
            if (zeroCount == 0 && windowSum < minSum) {
                minSum = windowSum;
                bestStart = start;
            }
        }

        if (bestStart == -1) return new int[] {-1, 0};
        return new int[] {bestStart, (int) minSum};
    }
}
